classDiagram
    class Codebase {
        +String name
        +String language
        +int linesOfCode
        +boolean isMaintainable()
    }

    class TestSuite {
        +String framework
        +int testCount
        +int coveragePercentage
        +boolean meetsThreshold()
    }

    class CodeQuality {
        +int cyclomaticComplexity
        +int codeSmells
        +boolean isHighQuality()
    }

    class CoverageThreshold {
        +int minimumCoverage
        +boolean isMet(int coverage)
    }

    Codebase "1" -- "1..*" TestSuite : contains
    Codebase "1" -- "1" CodeQuality : assesses
    TestSuite "1" -- "1" CoverageThreshold : checks

stateDiagram-v2
    [*] --> Planning
    Planning --> Development
    Development --> Testing
    Testing --> Staging
    Staging --> Production
    Production --> Monitoring
    Monitoring --> Feedback
    Feedback --> Planning

    state Planning {
        [*] --> Requirements
        Requirements --> Design
    }

    state Development {
        [*] --> Coding
        Coding --> CodeReview
        CodeReview --> Integration
    }

    state Testing {
        [*] --> UnitTests
        UnitTests --> IntegrationTests
        IntegrationTests --> UserAcceptance
    }

    state Staging {
        [*] --> PreProduction
        PreProduction --> FinalChecks
    }

    state Production {
        [*] --> Live
        Live --> Rollback
        Rollback --> Live
    }

    state Monitoring {
        [*] --> PerformanceMonitoring
        PerformanceMonitoring --> ErrorTracking
    }

    state Feedback {
        [*] --> UserFeedback
        UserFeedback --> Improvement
    }
